class BookMyShow {
public:
    BookMyShow(int n, int m) {
        this->n = n;
        this->m = m;
        this->seats = vector<vector<bool>>(n, vector<bool>(m, true));
    }

    vector<int> gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            if (seats[i].size() >= k) {
                int start = 0;
                while (start + k <= seats[i].size()) {
                    if (all(seats[i].begin() + start, seats[i].begin() + start + k)) {
                        return {i, start};
                    }
                    start++;
                }
            }
        }
        return {};
    }

    bool scatter(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            if (seats[i].size() >= k) {
                for (int start = 0; start + k <= seats[i].size(); start++) {
                    if (all(seats[i].begin() + start, seats[i].begin() + start + k)) {
                        for (int j = 0; j < k; j++) {
                            seats[i][start + j] = false;
                        }
                        return true;
                    }
                }
            }
        }
        return false;
    }
private:
    int n, m;
    vector<vector<bool>> seats;
    bool all(vector<bool>::iterator it, vector<bool>::iterator end) {
        while (it != end) {
            if (!*it) return false;
            it++;
        }
        return true;
    }
};

